      "keystrokes": "test -f /app/output/executor-audit.json && (jq '.cases|length' /app/output/executor-audit.json; jq '.cases[].name' -r /app/output/executor-audit.json) || (echo \"missing audit\"; exit 1)\n",
      "duration": 1.0
